mapper.select:
select ID, Type_risk as typeRisk, Year_matriculation as yearMatriculation, Power, 
       Cylinder_capacity as cylinderCapacity, Value_vehicle as valueVehicle, 
       N_doors as nDoors, Type_fuel as typeFuel, Length, Weight
from motor_insurance

    and ID = #{id}
    and Type_risk = #{typeRisk}
    and Type_fuel = #{typeFuel}
    and Year_matriculation = #{yearMatriculation}

order by ID desc
